import{_ as a,o as t,c as n,a3 as o}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"57. Annual Leave","description":"","frontmatter":{"title":"57. Annual Leave","eba":"Nurses and Midwives 2024-2028","topics":["leave","annual-leave","preliminary"]},"headers":[],"relativePath":"ebas/nurses-midwives/leave/57-annual-leave.md","filePath":"ebas/nurses-midwives/leave/57-annual-leave.md"}'),r={name:"ebas/nurses-midwives/leave/57-annual-leave.md"};function s(i,e,l,p,h,d){return t(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="_57-annual-leave" tabindex="-1">57. Annual Leave <a class="header-anchor" href="#_57-annual-leave" aria-label="Permalink to &quot;57. Annual Leave&quot;">​</a></h1><p>This clause does not apply to casual Employees.</p><p><strong>57.1</strong> Entitlement to Annual Leave</p><p><strong>(a)</strong> An Employee is entitled to 190 hours paid annual leave for each year of service.</p><p><strong>(b)</strong> A weekend worker is entitled to a further 38 hours paid annual leave for each year of service as follows:</p><p><strong>(i)</strong> For Full-Time Employees:</p><p><strong>(A)</strong> at the rate of 3.8 hours for each week in which ordinary hours were worked on a weekend (or part thereof) up to a maximum of 38 hours (10 weekends).</p><p><strong>(ii)</strong> For Part-Time Employees:</p><p><strong>(A)</strong> As a proportion of 3.8 hours for each week in which ordinary hours were worked on a weekend (or part thereof) up to a maximum of 10 weekends.</p><p>Example: If a part-time Employee who works 24 hours in a week that includes a weekend, they would accrue a proportion of 3.8 hours as follows: 24/38 x 3.8 = 2.4 hours.</p><p><strong>(c)</strong> Annual leave accrues progressively during a year of service according to the Employee&#39;s ordinary hours of work and accumulates from year to year.</p><p><strong>(i)</strong> Savings – weekend worker as at 30 June 2022</p><p>If an Employee was accruing six weeks of annual leave as at 30 June 2022 (or would have been but for the operation of a Flexible Working Arrangement, Individual Flexible Working Arrangement/s, or an absence from work on parental leave), the Employee will continue to accrue six weeks of annual leave unless or until:</p><p><strong>(A)</strong> the arrangement at subclauses 57.1(a) or (b) is more beneficial for the Employee;</p><p><strong>(B)</strong> the Employee changes Employers;</p><p><strong>(C)</strong> the Employee requests (and the Employer agrees) to move the Employee from full-time to part-time employment other than as part of a Flexible Working Arrangement, Individual Flexible Working Arrangement, family violence arrangement or reduced hours on return from parental leave); or</p><p><strong>(D)</strong> the Employee initiates a change that means they no longer perform weekend work. For example:</p><p>1) where an Employee requests a change to a different role that does not require the performance of weekend work;</p><p>2) where an Employee requests to move from a rotating or similar roster that includes weekends, to fixed shifts that do not include weekend work; or</p><p>3) where an Employee (at their request) relocates to a ward with a different system of work (for the removal of doubt, this does not include where an Employee requests to move to a ward with the same general system of work).</p><p><strong>57.2</strong> Taking paid annual leave</p><p><strong>(a)</strong> Paid annual leave may be taken for a period agreed between an Employee and their Employer.</p><p><strong>(b)</strong> The Employer must not unreasonably refuse to agree to a request by the Employee to take paid annual leave.</p><p><strong>(c)</strong> The Employer must publish how an Employee is to make an annual leave request.</p><p><strong>(d)</strong> Once annual leave is approved, it must not be unilaterally changed by the Employer. Where extraordinary circumstances arise, such that the Employer wishes the Employee to change the timing of their approved leave, any change may only occur through consultation and agreement.</p><p><strong>(e)</strong> Where it is likely the leave request will be rejected, the Employer and Employee will consult on alternate leave days within the 10 day period or, in the case of a high demand holiday period, the period between the date specified at 57.2(g)(i)(A) and 57.2(g)(i)(C).</p><p><strong>(f)</strong> Where the paid annual leave is for a period other than a high demand holiday period:</p><p><strong>(i)</strong> the Employee will submit a written request for annual leave at least 6 weeks prior to the first day of the proposed leave period/s unless it is not reasonable to do so in the circumstances; and</p><p><strong>(ii)</strong> within ten (10) weekdays of the leave request, the Employer will notify the Employee in writing that their annual leave request is approved or, if not approved, the reasons for the leave not being approved.</p><p><strong>(g)</strong> High Demand Holiday Periods</p><p><strong>(i)</strong> An Employer will develop and publish to affected Employees (which may be a specific ward or work area) requirements for a high demand holiday period. Where this occurs, the requirement must:</p><p><strong>(A)</strong> identify the high demand holiday period;</p><p><strong>(B)</strong> identify the date by which a written request for annual leave should be submitted; and</p><p><strong>(C)</strong> identify the date by which the Employer will notify the Employee in writing that their annual leave request is approved or, if not approved, the reasons for the leave not being approved.</p><p><strong>(ii)</strong> In determining applications for high-demand periods, the Employer will consider all the circumstances including but not limited to:</p><p><strong>(A)</strong> the Employer&#39;s operational needs;</p><p><strong>(B)</strong> the Employee&#39;s family responsibilities; and</p><p><strong>(C)</strong> whether previous leave applications for the same high demand period were or were not successful.</p><p>Example: A ward generally receives more applications for annual leave over school term breaks than it can accommodate. This means that school term breaks are &#39;high demand periods&#39; for that ward within the meaning of this subclause 57.2(f)) and the NUM/MUM must publish the information specified above at subclauses 57.2(g)(i)(A) to (C) and, when determining the applications, apply the considerations at subclause 57.2(f)(ii).</p><p><strong>57.3</strong> Excess annual leave accruals – general provision</p><p><strong>(a)</strong> An Employee has an excess leave accrual where the Employee has two years or more of annual leave entitlement accrued in accordance with this clause 57.</p><p><strong>(b)</strong> If an Employee has an excess leave accrual, the Employer or the Employee may seek to confer with the other and genuinely try to reach agreement on how to reduce or eliminate the excess leave accrual.</p><p>&#39;Genuinely trying to reach agreement&#39; will include:</p><p><strong>(i)</strong> providing the Employee a reasonable opportunity to submit a plan to reduce the leave to not less than eight (8) weeks within six months, subject to subclause 57.3(b)(ii) below; and</p><p><strong>(ii)</strong> the Employer not unreasonably refusing to agree to a leave reduction plan which includes saving leave for an extended vacation within 12 months of the date of agreement to the leave reduction plan.</p><p><strong>(c)</strong> The leave reduction plan is to be in writing and signed by both the Employer and the Employee.</p><p><strong>57.4</strong> Excess Annual leave accruals – no agreement reached</p><p><strong>(a)</strong> Direction by Employer</p><p>Where the Employer has genuinely tried to reach agreement with an Employee under subclause 57.4(b) but agreement is not reached (including because the Employee refuses to confer), the Employer may direct the Employee in writing to take one or more periods of paid annual leave.</p><p>However, in directing that the Employee take leave under this subclause 57.4(a):</p><p><strong>(i)</strong> the Employee cannot be directed to reduce the accrued leave to less than eight (8) weeks;</p><p><strong>(ii)</strong> the Employer cannot require an Employee to take any period of paid annual leave of less than one week;</p><p><strong>(iii)</strong> the Employer cannot require the Employee to take a period of paid annual leave beginning less than 8 weeks or more than 12 months after the direction is given; and</p><p><strong>(iv)</strong> the direction must not be inconsistent with any leave arrangement agreed by the Employer and Employee.</p><p><strong>(b)</strong> Where the Employer issues a Direction</p><p>Where the Employer issues a direction to the Employee to take paid annual leave in accordance with paragraph (a):</p><p><strong>(i)</strong> the Employee must take paid annual leave in accordance with that direction; and</p><p><strong>(ii)</strong> the Employee may request to take a period of paid annual leave as if the direction had not been given.</p><p><strong>(c)</strong> Request by Employee for Leave</p><p>If the Employee has genuinely tried to reach agreement with the Employer under subclause 57.4(b) but agreement is not reached (including because the Employer refuses to confer), the Employee may give a written notice to the Employer requesting to take one or more periods of paid annual leave.</p><p>However, a notice under this subclause:</p><p><strong>(i)</strong> may only be given if the Employee has had an excess leave accrual for more than 6 months at the time of giving the notice;</p><p><strong>(ii)</strong> may only be given if the Employee has not been given a direction under subclause 57.4(a) that, when any other paid annual leave arrangements are taken into account would eliminate the Employee&#39;s excess accrual;</p><p><strong>(iii)</strong> must not, if granted, result in the Employee&#39;s remaining accrued entitlement to paid annual leave being, at any time, less than 6 weeks when other paid annual leave arrangements are taken into account;</p><p><strong>(iv)</strong> must not provide for the Employee to take any period of paid annual leave of less than one week;</p><p><strong>(v)</strong> must not provide for the Employee to take a period of paid annual leave beginning less than 8 weeks or more than 12 months, after the notice is given;</p><p><strong>(vi)</strong> must not be inconsistent with any leave arrangement agreed by the Employer and Employee; and</p><p><strong>(vii)</strong> must not be for more than 1 full year&#39;s entitlement to annual leave as prescribed by clause 57.1 above.</p><p><strong>(d)</strong> Where the Employee requests leave by notice</p><p>Where the Employee gives written notice to the Employer to take one or more periods of paid annual leave in accordance with subclause 57.4(c), the Employer must grant paid annual leave requested by the notice under subclause 57.4(c).</p><p><strong>(e)</strong> Disputes regarding excess annual leave</p><p>Without limiting the Dispute Resolution Procedure of the Agreement, either an Employee or Employer (or their representative/s) may refer a dispute about the following matters to the Commission:</p><p><strong>(i)</strong> a dispute about whether the Employer or Employee has requested a meeting and genuinely tried to reach agreement;</p><p><strong>(ii)</strong> a dispute about whether the Employer has unreasonably refused to agree to a request by the Employee to take paid annual leave;</p><p><strong>(iii)</strong> a dispute about whether a direction to take leave complies with the clause; or</p><p><strong>(iv)</strong> a dispute about a leave reduction plan referenced in subclauses 57.4(b) and (c).</p><p><strong>57.5</strong> Short periods of annual leave</p><p>Paid annual leave under this clause can be taken in periods less than an Employee&#39;s ordinary fortnight (short period), including single days in which case any notice period may be waived by agreement.</p><p><strong>57.6</strong> Employee not taken to be on paid annual leave at certain times</p><p><strong>(a)</strong> Public Holidays</p><p>See also <a href="/eba/ebas/medical-specialists/leave/56-public-holidays.html">clause 56</a> (public holidays).</p><p>If an Employee takes paid annual leave during a period that includes a public holiday, the Employee is taken not to be on paid annual leave on that day.</p><p><strong>(b)</strong> Other Periods of Leave</p><p>See also <a href="/eba/ebas/nurses-midwives/leave/61-personal-leave.html">clauses 61</a> (Personal Leave) and 65 (Compassionate Leave).</p><p><strong>(i)</strong> An Employee may take other types of leave, such as personal leave or compassionate leave whilst on annual leave. An Employee is taken not to be on paid annual leave whilst on other leave and the Employee&#39;s paid annual leave accrual will be amended to reflect this. These provisions do not apply to unpaid parental leave.</p><p><strong>(ii)</strong> An Employee taking personal leave whilst on annual leave will provide the Employer with evidence in accordance with <a href="/eba/ebas/nurses-midwives/leave/61-personal-leave.html">clause 61</a> (Personal Leave).</p><p><strong>(iii)</strong> Where an Employee takes other leave during annual leave, any annual leave loading received for a period that is no longer annual leave is taken to have been paid in advance as required in clause</p><p><strong>57.7</strong> (Payment for leave) or may be deducted from any payment required to be made under subclause 57.11(a) (Effect of termination on annual leave).</p><p><strong>57.7</strong> Payment for leave</p><p><strong>(a)</strong> Employees will receive their ordinary pay and any amount required by clause</p><p><strong>57.8</strong> (Annual leave loading or penalties) during periods of annual leave. Ordinary pay for the purposes of this clause means remuneration for the Employee&#39;s normal weekly number of hours of work calculated at the ordinary time rate of pay provided that:</p><p><strong>(i)</strong> where an Employee has performed higher duties for an aggregate period of three months or more in a 12-month period, ordinary pay will be adjusted proportionally to reflect the period during which higher duties were performed; and</p><p><strong>(ii)</strong> normal weekly hours for a part-time Employee who performs additional shifts will reflect the additional hours worked over the 12- month period.</p><p><strong>(b)</strong> Payment for paid annual leave will be in advance for the period of such leave except for a short period.</p><p><strong>57.8</strong> Annual leave loading or penalties</p><p><strong>(a)</strong> In addition to ordinary pay (as defined) an Employee will receive the higher of:</p><p><strong>(i)</strong> leave loading of 17.5% calculated on the relevant rate of salary prescribed in <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a>, subject to the cap at clause 57.9; or</p><p><strong>(ii)</strong> the payments listed below which the Employee would have received had the Employee not been on leave:</p><p><strong>(A)</strong> shift allowances (<a href="/eba/ebas/nurses-midwives/allowances/34-shift-allowance.html">clause 34</a>);</p><p><strong>(B)</strong> special rates for Saturdays and Sundays (<a href="/eba/ebas/nurses-midwives/hours-of-work/48-special-rates-for-saturdays-and-sundays.html">clause 48</a>);</p><p><strong>(C)</strong> qualification allowance (<a href="/eba/ebas/nurses-midwives/allowances/31-qualification-allowance.html">clause 31</a>);</p><p><strong>(D)</strong> uniform allowances (<a href="/eba/ebas/nurses-midwives/allowances/38-uniform-and-laundry-allowance.html">clause 38</a>); and</p><p><strong>(E)</strong> RIPRN allowance (<a href="/eba/ebas/nurses-midwives/allowances/32-rural-and-isolated-practice-allowance.html">clause 32</a>).</p><p><strong>(b)</strong> From 1 June 2024, leave loading under subclause 57.7(a)(i) is payable on:</p><p><strong>(i)</strong> a maximum of 190 hours in respect of any year of employment, and</p><p><strong>(ii)</strong> the Employee&#39;s weekly ordinary pay subject to the cap (as defined).</p><p><strong>57.9</strong> The cap under subclause 57.8(b)(ii) is the weekly rate prescribed by this Agreement for a NM5C.</p><p><strong>57.10</strong> To determine which payments the Employee would have received had the Employee not been on leave for the purpose of subclause 57.8(a)(ii), this will be done either by:</p><p><strong>(a)</strong> the projected roster, being the roster the Employee would have worked had they not been on leave; or</p><p><strong>(b)</strong> where there is no projected roster, the rosters for the 12 weeks immediately preceding the leave excluding any period during which the Employee was not on the roster (for example, because of attendance at approved professional development or another form of paid leave).</p><p><strong>57.11</strong> Effect of termination on annual leave</p><p><strong>(a)</strong> Where an Employee&#39;s employment ends for any reason, the Employer must pay to the Employee any untaken accrued annual leave. The amount payable to the Employee is the amount the Employee would have received had the Employee taken the leave at the time of termination, including any payment under clause</p><p><strong>57.8</strong> (Annual leave loading or penalties).</p><p><strong>(b)</strong> If annual leave has been taken in advance and, at the time the employment terminates, the Employee has a negative paid annual leave accrual, the Employer may deduct a sum equal to the negative annual leave accrual (at the amount paid at the time the annual leave was taken in advance) from any remuneration payable to the Employee upon termination of employment.</p><p><strong>57.12</strong> ADOs and annual leave</p><p>See clause 0 (Accrued Days Off).</p><p>Plain language terms: holidays, vacation, recreation leave, holiday pay.</p>',117)])])}const g=a(r,[["render",s]]);export{m as __pageData,g as default};
